import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, Compass, MessageSquare, 
  Handshake, Bell, UserCircle, Settings 
} from 'lucide-react';

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  const navItems = [
    { name: 'Dashboard', icon: <LayoutDashboard size={20} />, path: '/dashboard' },
    { name: 'Explore', icon: <Compass size={20} />, path: '/explore' },
    { name: 'Messages', icon: <MessageSquare size={20} />, path: '/messages' },
    // THE NEW BAR
    { name: 'Send Request', icon: <Handshake size={20} />, path: '/barter-request' }, 
    { name: 'Notifications', icon: <Bell size={20} />, path: '/notifications' },
    { name: 'Profile', icon: <UserCircle size={20} />, path: '/profile' },
    { name: 'Settings', icon: <Settings size={20} />, path: '/settings' },
  ];

  return (
    <div className="w-64 bg-white border-r min-h-screen p-6 flex flex-col space-y-2">
      <div className="mb-10 px-4">
        <h1 className="text-2xl font-black text-teal-600 tracking-tighter">WERTECH</h1>
      </div>

      <nav className="flex-1 space-y-2">
        {navItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <button
              key={item.name}
              onClick={() => navigate(item.path)}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-[20px] font-bold transition-all duration-200 ${
                isActive 
                  ? 'bg-teal-600 text-white shadow-lg' 
                  : 'text-slate-400 hover:bg-slate-50'
              }`}
            >
              {item.icon}
              <span className="text-sm">{item.name}</span>
            </button>
          );
        })}
      </nav>
    </div>
  );
}
